namespace sv_dc737f23f3fd4520a9add713f11ac109;

public enum Theme
{
    Light,
    Dark,
    System
}

public record ThemeInfo(Theme Theme, string AccentColor)
{
    public static ThemeInfo Default => new(Theme.Light, "#0d6efd");
}

@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<span class="theme-indicator" style="color: @Theme?.AccentColor">
    @GetIcon() @Theme?.Theme
</span>
<button class="btn btn-sm btn-outline-secondary ms-2" @onclick="CycleTheme">
    Toggle Theme
</button>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private string GetIcon() => Theme?.Theme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    private async Task CycleTheme()
    {
        var current = Theme ?? ThemeInfo.Default;
        var next = current.Theme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            _ => Theme.Light
        };
        await ThemeSource.NotifyChangedAsync(current with { Theme = next });
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card p-4" style="max-width: 400px;">
    <div class="mb-3">
        <label class="form-label fw-bold">Theme</label>
        <select class="form-select" value="@currentTheme" @onchange="OnThemeChanged">
            @foreach (var t in Enum.GetValues<Theme>())
            {
                <option value="@t">@t</option>
            }
        </select>
    </div>

    <div class="mb-3">
        <label class="form-label fw-bold">Accent Color</label>
        <input type="color" class="form-control form-control-color"
               value="@currentAccent" @onchange="OnAccentChanged" />
        <small class="text-muted">@currentAccent</small>
    </div>

    <div class="mt-3 p-3 border rounded" style="border-color: @currentAccent !important;">
        <strong>Preview:</strong>
        <span style="color: @currentAccent;">
            @GetIcon() @currentTheme mode with accent @currentAccent
        </span>
    </div>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private Theme currentTheme;
    private string currentAccent = ThemeInfo.Default.AccentColor;

    protected override void OnParametersSet()
    {
        var t = Theme ?? ThemeInfo.Default;
        currentTheme = t.Theme;
        currentAccent = t.AccentColor;
    }

    private async Task OnThemeChanged(ChangeEventArgs e)
    {
        currentTheme = Enum.Parse<Theme>(e.Value?.ToString() ?? "Light");
        await NotifyChange();
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        currentAccent = e.Value?.ToString() ?? ThemeInfo.Default.AccentColor;
        await NotifyChange();
    }

    private async Task NotifyChange()
    {
        await ThemeSource.NotifyChangedAsync(new ThemeInfo(currentTheme, currentAccent));
    }

    private string GetIcon() => currentTheme switch
    {
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };
}

