     [CascadingParameter]
     private ThemeInfo? CurrentTheme { get; set; }

     private sv_dc737f23f3fd4520a9add713f11ac109.Theme currentTheme;
     private string currentAccent = ThemeInfo.Default.AccentColor;

     protected override void OnParametersSet()
     {
         var t = CurrentTheme ?? ThemeInfo.Default;
         currentTheme = t.Theme;
         currentAccent = t.AccentColor;
     }

     private async Task OnThemeChanged(ChangeEventArgs e)
     {
